  1→import SwiftUI
  2→
  3→/// Main view — authenticates, then shows four-tab navigation.
  4→struct ContentView: View {
  5→    @State private var authVM = AuthViewModel()
  6→    @State private var sessionVM = SessionViewModel()
  7→    @State private var recordingVM = RecordingViewModel()
  8→    @State private var uploadVM = UploadViewModel()
  9→    @State private var patientVM = PatientViewModel()
 10→    @State private var transcriptionVM = TranscriptionViewModel()
 11→    @State private var viewingTranscript: TranscriptViewerItem?
 12→    @State private var activeSessionId: String?
 13→    @State private var selectedTab = 0
 14→
 15→    var body: some View {
 16→        Group {
 17→            switch authVM.authState {
 18→            case .unauthenticated, .authenticating, .tokenExpired:
 19→                LoginView(authViewModel: authVM)
 20→                    .frame(minWidth: 500, minHeight: 600)
 21→
 22→            case .authenticated:
 23→                authenticatedContent
 24→            }
 25→        }
 26→        .background(Color.pabloCream)
 27→        .preferredColorScheme(.light)
 28→    }
 29→
 30→    private var authenticatedContent: some View {
 31→        TabView(selection: $selectedTab) {
 32→            todayTab
 33→            sessionsTab
 34→            patientsTab
 35→            settingsTab
 36→        }
 37→        .frame(minWidth: 500, minHeight: 600)
 38→        .task { await configureAndLoad() }
 39→        .alert("Recording Error", isPresented: $recordingVM.showError, presenting: recordingVM.errorMessage) { _ in
 40→            Button("OK") {}
 41→        } message: { message in
 42→            Text(message)
 43→        }
 44→        .alert("Upload Error", isPresented: $uploadVM.showError, presenting: uploadVM.errorMessage) { _ in
 45→            Button("OK") {}
 46→        } message: { message in
 47→            Text(message)
 48→        }
 49→        .alert("Patient Error", isPresented: $patientVM.showError, presenting: patientVM.errorMessage) { _ in
 50→            Button("OK") {}
 51→        } message: { message in
 52→            Text(message)
 53→        }
 54→        .alert("Session Error", isPresented: $sessionVM.showError, presenting: sessionVM.errorMessage) { _ in
 55→            Button("OK") {}
 56→        } message: { message in
 57→            Text(message)
 58→        }
 59→        .task {
 60→            while !Task.isCancelled {
 61→                try? await Task.sleep(for: .seconds(300))
 62→                guard !Task.isCancelled else { break }
 63→                await transcriptionVM.retryPendingUploads()
 64→            }
 65→        }
 66→        .sheet(item: $viewingTranscript) { item in
 67→            TranscriptViewerView(transcript: item.text, recordingDate: item.recordingDate)
 68→        }
 69→        .onChange(of: uploadVM.backendURL) { _, newURL in
 70→            patientVM.backendURL = newURL
 71→            sessionVM.backendURL = newURL
 72→        }
 73→    }
 74→
 75→    // MARK: - Setup
 76→
 77→    private func configureAndLoad() async {
 78→        let serverURL = KeychainManager.getToken(forKey: .authServerURL)
 79→            ?? authVM.authServerURL
 80→        if let config = try? await fetchServerConfig(authServerURL: serverURL) {
 81→            uploadVM.backendURL = config.apiUrl
 82→            patientVM.backendURL = config.apiUrl
 83→            sessionVM.backendURL = config.apiUrl
 84→            if KeychainManager.getToken(forKey: .firebaseAPIKey) == nil {
 85→                if let key = config.firebaseApiKey, !key.isEmpty {
 86→                    KeychainManager.saveToken(key, forKey: .firebaseAPIKey)
 87→                }
 88→            }
 89→        }
 90→
 91→        uploadVM.configureAuth { [authVM] in try await authVM.getValidToken() }
 92→        patientVM.configureAuth { [authVM] in try await authVM.getValidToken() }
 93→        sessionVM.configureAuth { [authVM] in try await authVM.getValidToken() }
 94→
 95→        do {
 96→            _ = try await authVM.getValidToken()
 97→        } catch {
 98→            authVM.signOut()
 99→        }
100→
101→        await sessionVM.loadTodaySessions()
102→        await patientVM.loadPatients()
103→        await recordingVM.loadAudioSources()
104→        await uploadVM.checkBackendHealth()
105→
106→        transcriptionVM.backendURL = uploadVM.backendURL
107→        transcriptionVM.configureAuth { [authVM] in try await authVM.getValidToken() }
108→        await transcriptionVM.retryPendingUploads()
109→
110→        recordingVM.onRecordingCompleted = { [transcriptionVM] recording in
111→            transcriptionVM.transcribeIfNeeded(recording)
112→        }
113→
114→        ModelManager.shared.onModelDownloaded = { [transcriptionVM] preset in
115→            Task { await transcriptionVM.processAwaitingModelRecordings(downloadedPreset: preset) }
116→        }
117→    }
118→
119→    // MARK: - Session orchestration
120→
121→    private func startSession(_ session: Session) {
122→        Task {
123→            guard await sessionVM.startSession(session.id) != nil else { return }
124→            activeSessionId = session.id
125→            recordingVM.activeSessionId = session.id
126→            await recordingVM.startRecording()
127→            VideoLaunchService.launch(session: session)
128→        }
129→    }
130→
131→    private func handleQuickStart(_ patient: Patient) {
132→        Task {
133→            guard let session = await sessionVM.createAdHocSession(patientId: patient.id) else { return }
134→            guard await sessionVM.startSession(session.id) != nil else { return }
135→            activeSessionId = session.id
136→            recordingVM.activeSessionId = session.id
137→            await recordingVM.startRecording()
138→        }
139→    }
140→
141→    // MARK: - Lookups
142→
143→    private func transcriptionStateForSession(_ sessionId: String) -> TranscriptionState? {
144→        guard let recordingId = recordingVM.sessionRecordingMap[sessionId] else {
145→            return nil
146→        }
147→        return transcriptionVM.states[recordingId]
148→    }
149→
150→    private func hasRecordingForSession(_ sessionId: String) -> Bool {
151→        recordingVM.recordingForSession(sessionId) != nil
152→    }
153→
154→    private func transcribeSession(_ session: Session) {
155→        guard let recording = recordingVM.recordingForSession(session.id) else {
156→            return
157→        }
158→        Task { await transcriptionVM.transcribe(recording) }
159→    }
160→
161→    private func showTranscript(for session: Session) {
162→        guard let text = transcriptionStateForSession(session.id)?.transcript
163→        else { return }
164→        let date = ISO8601DateFormatter().date(from: session.scheduledAt ?? "")
165→            ?? Date()
166→        viewingTranscript = TranscriptViewerItem(
167→            id: UUID(),
168→            text: text,
169→            recordingDate: date
170→        )
171→    }
172→
173→    private func playSession(_ session: Session) {
174→        guard let recording = recordingVM.recordingForSession(session.id) else {
175→            return
176→        }
177→        recordingVM.playRecording(recording)
178→    }
179→
180→    // MARK: - Tabs
181→
182→    private var todayTab: some View {
183→        DayView(
184→            sessionVM: sessionVM,
185→            patients: patientVM.patients,
186→            isLoadingPatients: patientVM.isLoading,
187→            patientSearchText: $patientVM.searchText,
188→            recordingState: recordingVM.recordingState,
189→            recordingDuration: recordingVM.duration,
190→            pendingUploadCount: transcriptionVM.pendingUploadCount,
191→            awaitingModelCount: transcriptionVM.awaitingModelCount,
192→            transcriptionStateForSession: { transcriptionStateForSession($0) },
193→            hasRecordingForSession: { hasRecordingForSession($0) },
194→            playingSessionId: recordingVM.playingSessionId,
195→            onStartSession: { startSession($0) },
196→            onQuickStart: { handleQuickStart($0) },
197→            onStopRecording: {
198→                Task {
199→                    await recordingVM.stopRecording()
200→                    recordingVM.activeSessionId = nil
201→                    if let sessionId = activeSessionId {
202→                        _ = await sessionVM.endSession(sessionId)
203→                        activeSessionId = nil
204→                    }
205→                    await sessionVM.loadTodaySessions()
206→                }
207→            },
208→            onRetryUploads: { Task { await transcriptionVM.forceRetryPendingUploads() } },
209→            onSwitchToSettings: { selectedTab = 3 },
210→            onViewTranscript: { showTranscript(for: $0) },
211→            onTranscribeSession: { transcribeSession($0) },
212→            onPlaySession: { playSession($0) },
213→            onStopPlayback: { recordingVM.stopPlayback() },
214→            onEndSession: { session in
215→                Task {
216→                    _ = await sessionVM.endSession(session.id)
217→                    await sessionVM.loadTodaySessions()
218→                }
219→            },
220→            activeSessionId: activeSessionId
221→        )
222→        .tabItem { Label("Today", systemImage: "calendar") }
223→        .tag(0)
224→    }
225→
226→    private var sessionsTab: some View {
227→        SessionHistoryView(
228→            viewModel: sessionVM,
229→            patients: patientVM.patients,
230→            pendingUploadCount: transcriptionVM.pendingUploadCount,
231→            transcriptionStateForSession: { transcriptionStateForSession($0) },
232→            hasRecordingForSession: { hasRecordingForSession($0) },
233→            playingSessionId: recordingVM.playingSessionId,
234→            onRetryUploads: { Task { await transcriptionVM.forceRetryPendingUploads() } },
235→            onViewTranscript: { showTranscript(for: $0) },
236→            onTranscribeSession: { transcribeSession($0) },
237→            onPlaySession: { playSession($0) },
238→            onStopPlayback: { recordingVM.stopPlayback() }
239→        )
240→        .tabItem { Label("Sessions", systemImage: "list.clipboard") }
241→        .tag(1)
242→    }
243→
244→    private var patientsTab: some View {
245→        PatientListView(viewModel: patientVM)
246→            .tabItem { Label("Patients", systemImage: "person.2") }
247→            .tag(2)
248→    }
249→
250→    private var settingsTab: some View {
251→        SettingsView(
252→            backendURL: $uploadVM.backendURL,
253→            authServerURL: $authVM.authServerURL,
254→            selectedMicID: $recordingVM.selectedMicID,
255→            encryptionEnabled: $recordingVM.encryptionEnabled,
256→            debugEnableMic: $recordingVM.debugEnableMic,
257→            debugEnableSystem: $recordingVM.debugEnableSystem,
258→            userEmail: authVM.authenticatedEmail,
259→            availableMics: recordingVM.availableMics,
260→            isBackendReachable: uploadVM.isBackendReachable,
261→            bluetoothRoutingConflict: recordingVM.bluetoothRoutingConflict,
262→            bluetoothRecommendation: recordingVM.bluetoothRecommendation,
263→            systemAudioPermitted: recordingVM.systemAudioPermitted,
264→            recordingState: recordingVM.recordingState,
265→            diagnostics: recordingVM.debugDiagnostics,
266→            onCheckHealth: { Task { await uploadVM.checkBackendHealth() } },
267→            onGenerateTestTone: { recordingVM.generateTestTone() },
268→            onSignOut: { authVM.signOut() }
269→        )
270→        .tabItem { Label("Settings", systemImage: "gear") }
271→        .tag(3)
272→    }
273→}
