  1→import SwiftUI
  2→
  3→/// A single session row for the day view — shows patient name, time, status badge, and video platform.
  4→struct SessionRowView: View {
  5→    let session: Session
  6→    var patientLookup: ((String) -> Patient?)?
  7→    var transcriptionState: TranscriptionState?
  8→    var hasRecording = false
  9→    var isPlaying = false
 10→    var onStart: (() -> Void)?
 11→    var onViewTranscript: (() -> Void)?
 12→    var onTranscribe: (() -> Void)?
 13→    var onPlay: (() -> Void)?
 14→    var onStopPlayback: (() -> Void)?
 15→    var onEndSession: (() -> Void)?
 16→    @State private var isPulsing = false
 17→
 18→    var body: some View {
 19→        HStack(spacing: 12) {
 20→            initialsAvatar
 21→            timeColumn
 22→            Divider().frame(height: 32)
 23→            patientInfo
 24→            Spacer()
 25→            if let platform = session.videoPlatform {
 26→                videoPlatformIcon(platform)
 27→            }
 28→            trailingContent
 29→        }
 30→        .padding(.horizontal, 16)
 31→        .padding(.vertical, 12)
 32→        .cardBackground()
 33→    }
 34→
 35→    // MARK: - Initials avatar
 36→
 37→    private var initialsAvatar: some View {
 38→        ZStack {
 39→            Circle()
 40→                .fill(avatarColor.opacity(0.18))
 41→                .frame(width: 36, height: 36)
 42→                .overlay {
 43→                    Circle()
 44→                        .stroke(Color.pabloSage, lineWidth: 2)
 45→                        .opacity(isPulsing ? 0.35 : 0.18)
 46→                        .animation(pulseAnimation, value: isPulsing)
 47→                        .opacity(session.status == .inProgress ? 1 : 0)
 48→                }
 49→            Text(initials)
 50→                .font(.system(size: 14, weight: .semibold))
 51→                .foregroundStyle(Color.pabloBrownDeep)
 52→        }
 53→        .onAppear {
 54→            if session.status == .inProgress { isPulsing = true }
 55→        }
 56→    }
 57→
 58→    private var avatarColor: Color {
 59→        session.status == .inProgress ? Color.pabloSage : Color.pabloHoney
 60→    }
 61→
 62→    private var initials: String {
 63→        if let patient = session.patient {
 64→            let first = patient.firstName.first.map(String.init) ?? ""
 65→            let last = patient.lastName.first.map(String.init) ?? ""
 66→            return "\(first)\(last)".uppercased()
 67→        }
 68→        if let id = session.patientId, let patient = patientLookup?(id) {
 69→            let first = patient.firstName.first.map(String.init) ?? ""
 70→            let last = patient.lastName.first.map(String.init) ?? ""
 71→            return "\(first)\(last)".uppercased()
 72→        }
 73→        return "?"
 74→    }
 75→
