301→        if let date = formatter.date(from: scheduledAt) {
302→            return timeString(from: date)
303→        }
304→        formatter.formatOptions = [.withInternetDateTime]
305→        if let date = formatter.date(from: scheduledAt) {
306→            return timeString(from: date)
307→        }
308→        return "--:--"
309→    }
