142→    /// Derives two-letter initials from the display name.
143→    private var initials: String {
144→        let words = displayName.split(separator: " ").map(String.init)
145→        if words.count >= 2 {
146→            if let first = words.first?.first, let last = words.last?.first {
147→                return "\(first)\(last)".uppercased()
148→            }
149→        }
150→        if let word = words.first {
151→            let chars = word.prefix(2)
152→            return chars.uppercased()
153→        }
154→        return "?"
155→    }
