107→/// Compact patient row for the quick-start picker.
108→private struct QuickStartPatientRow: View {
109→    let patient: Patient
110→    let onTap: () -> Void
111→
112→    var body: some View {
113→        Button(action: onTap) {
114→            HStack(spacing: 12) {
115→                initialsAvatar
116→                Text(displayName)
117→                    .font(.pabloBody(14))
118→                    .foregroundStyle(Color.pabloBrownDeep)
119→                Spacer()
120→            }
121→            .padding(.horizontal, 12)
122→            .padding(.vertical, 10)
123→            .cardBackground()
124→        }
125→        .buttonStyle(.plain)
126→    }
127→
128→    private var initialsAvatar: some View {
129→        ZStack {
130→            Circle()
131→                .fill(Color.pabloHoney.opacity(0.18))
132→                .frame(width: 32, height: 32)
133→            Text(initials)
134→                .font(.system(size: 13, weight: .semibold))
135→                .foregroundStyle(Color.pabloBrownDeep)
136→        }
137→    }
138→
139→    private var displayName: String {
140→        let raw = patient.fullName
141→        guard raw.contains(", ") else { return raw.capitalized }
142→        let parts = raw.components(separatedBy: ", ")
143→        guard parts.count >= 2 else { return raw.capitalized }
144→        return [parts[1], parts[0]]
145→            .map(\.capitalized)
146→            .joined(separator: " ")
147→    }
148→
149→    private var initials: String {
150→        let words = displayName.split(separator: " ").map(String.init)
151→        if let first = words.first?.first, let last = words.last?.first, words.count >= 2 {
152→            return "\(first)\(last)".uppercased()
153→        }
154→        if let word = words.first {
155→            return String(word.prefix(2)).uppercased()
156→        }
157→        return "?"
158→    }
159→}
