 5→@main
 6→struct PabloCompanionApp: App {
 7→    init() {
 8→        registerFonts()
 9→    }
10→
11→    var body: some Scene {
12→        WindowGroup {
13→            ContentView()
14→                .task {
15→                    await requestScreenCapturePermission()
16→                }
17→        }
18→        .windowResizability(.contentMinSize)
19→    }
20→
21→    /// Registers bundled variable fonts (DM Sans, Fraunces) so SwiftUI
22→    /// Font.custom() can resolve them by family name.
23→    private func registerFonts() {
24→        let fontNames = ["DMSans.ttf", "Fraunces.ttf"]
25→        for name in fontNames {
26→            guard let url = Bundle.main.url(forResource: name, withExtension: nil) else {
27→                assertionFailure("Font not found in bundle: \(name)")
28→                continue
29→            }
30→            CTFontManagerRegisterFontsForURL(url as CFURL, .process, nil)
31→        }
32→    }
33→
34→    /// Triggers the ScreenCaptureKit permission prompt, which reliably
35→    /// registers the app in System Settings > Privacy & Security >
36→    /// Screen & System Audio Recording.
37→    private func requestScreenCapturePermission() async {
38→        do {
39→            // This call triggers the system permission prompt on first launch.
40→            // It will throw if permission is denied, which is fine — we handle
41→            // that gracefully in the capture layer.
42→            _ = try await SCShareableContent.excludingDesktopWindows(
43→                false, onScreenWindowsOnly: false
44→            )
45→        } catch {
46→            // Expected on first launch before permission is granted
47→        }
48→    }
49→}
